    var opcionesHora = { hour: '2-digit', minute: '2-digit' };

    var dia = fecha.toLocaleDateString('es-ES', opcionesDia);
    var hora = fecha.toLocaleTimeString('es-ES', opcionesHora);
    return `${dia}, ${hora}`;
}

var fechaFormateada = formatearFecha(utlActu);

msg.payload = {
    ciudad,
    provincia,
    pais,
    utlActu: fechaFormateada,
    tempMax,
    tempMin,
    probLluvia,
    humedad,
    uv,
    precipitacionTotal,
    velMaxViento,
    icon,
    estado,
};

return msg;
